  "GL-QUOTES:TABLE": {
   "name": "GL-QUOTES:TABLE",
   "kind": "constant",
   "file": "other-misc.zil",
   "line": 904,
   "value": "<PTABLE <PLTABLE 38 \"Visiting Hours: 7:00 a.m - 6:00 p.m.\"> <PLTABLE 18 \"\"Quiet, please.\"\"> <PLTABLE 36 \"        CHAMBER OF HORRORS        \" \"ABANDON HOPE ALL YE WHO ENTER HERE\"> <PLTABLE 32 \"MUSEUM HOURS:  8 a.m. - 6 p.m.\"> <PLTABLE 8 \"\"1666\"\"> <PLTABLE 38 \"This a replica of the rowboat in    \" \"which Captain Bligh was set adrift  \" \"after the infamous Mutiny on the    \" \"Bounty. Bligh and his men rowed 3600\" \"miles in 45 days, and lived to see  \" \"the mutineers brought to justice.    \"> <PLTABLE 38 \"For your convenience, the Bank shall\" \"be closed for the entire Jubilee    \" \"weekend. Thank you for your         \" \"patronage.                           \"> <PLTABLE 38 \"        THE TOWER IS CLOSED.         \" 0 \"    WE REGRET ANY INCONVENIENCE.     \" 0 \"          HAVE A NICE DAY.           \"> <PLTABLE 38 \"During the battle of Copenhagen,    \" \"Lord Nelson's commander-in-chief ran\" \"the signal to \"discontinue action\"  \" \"up his mast. Knowing the battle     \" \"could yet be won, Nelson clapped his\" \"telescope to his blind eye and said,\" \"\"I do not see the signal.\" His      \" \"subsequent attack led to victory and\" \"a secure place for Nelson in British\" \"history.                             \"> <PLTABLE 17 \" No Loitering. \" 0 \"This means YOU!\"> <PLTABLE 13 \"BAR OF GOLD\"> <PLTABLE 38 \"\"Many monarchs are buried in        \" \"Westminster. But only one died here.\" \"It happened on March 20th, 1413, and\" \"the event was later made famous in a\" \"scene written by Shakespeare:\"      \" 0 \"\"It hath been prophesied to me many \" \"   years                            \" \"I should not die but in Jerusalem,  \" \"Which vainly I supposed the Holy    \" \"   Land.                             \" \"But bear me to that chamber, there  \" \"   I'll lie,                        \" \"In that Jerusalem shall Harry die.\" \" 0 \"\"Henry IV, Part II, Act V\"          \"> <PLTABLE 17 \"   HELD OVER   \" 0 \"SIXTH BIG WEEK!\" 0 \"THE MOUSETRAP!!\"> <PLTABLE 39 \"This sign unintentionally left blank.\"> ;<PLTABLE 29 \"THE SIGN OF THE RED HERRING\">>"
  },
